SET session_replication_role = replica;

INSERT INTO public.questions VALUES ('c85955d6-4be8-436d-9007-1e278a1a0079', '9a65602e-4e21-46d7-b87f-5578edb82a92', 'radio', 'Questions 15–21', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Darren’s Bike Hire is open 7 days a week"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "All bicycles cost the same to hire"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You have to pay extra for a basket and lock"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Reservations are advised at some times of year"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "All bikes come with child seats"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The deposit is non-refundable"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It can be cheaper to hire a bike during the winter months"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">15. Đáp án: {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc cung cấp giá thuê theo ngày, tuần và thông tin liên lạc.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong toàn bộ văn bản <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"34\">không có thông tin</strong> nào đề cập đến việc cửa hàng mở cửa 7 ngày một tuần hay có nghỉ ngày nào không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">16. Đáp án: {TRUE}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"17\">large selection of bikes</strong> are all available for hire at only <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"77\">£25.00 a day</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản nêu rõ một bộ sưu tập xe lớn nhưng tất cả đều có chung mức giá thuê là £25.00/ngày.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">17. Đáp án: {FALSE}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…at only £25.00 a day (<strong data-path-to-node=\"8,0,0\" data-index-in-node=\"37\">cost of basket and lock inclusive</strong>).”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “inclusive” nghĩa là đã bao gồm trong giá. Vì vậy, bạn <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"70\">không phải trả thêm tiền</strong> (pay extra) cho giỏ và khóa xe.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">18. Đáp án: {TRUE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Just email… to ensure that there is a bike waiting for you… This is <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"84\">particularly necessary during the school holiday period of July and August</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc đặt trước (reservations) được khuyến nghị là “đặc biệt cần thiết” vào khoảng thời gian nghỉ lễ tháng 7 và tháng 8.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">19. Đáp án: {FALSE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and, <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">for those too small to pedal themselves</strong>, there are bikes fitted with child seats.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chỉ những xe dành cho trẻ quá nhỏ không tự đạp được mới được lắp ghế trẻ em, chứ <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"93\">không phải tất cả các xe</strong> (all bikes) đều có.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">20. Đáp án: {FALSE}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In addition, a £40.00 deposit must be paid. <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"56\">This is returned to the hirer on the safe return of the bicycle</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tiền đặt cọc sẽ được hoàn trả (returned) khi trả xe an toàn, trái ngược với ý “không hoàn lại” (non-refundable) trong câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">21. Đáp án: {TRUE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Rates are reduced for longer periods, <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"50\">especially in winter</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Rates are reduced” nghĩa là giá rẻ hơn (cheaper), đặc biệt là vào mùa đông.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e204b2c1-e045-4022-8960-8a151ab85827', '9a65602e-4e21-46d7-b87f-5578edb82a92', 'fillup', 'Questions 22–27', '<p class="MsoNormal">Complete the sentences below</p>
<p class="MsoNormal">Choose <strong>NO MORE THAN THREE WORDS AND/OR A NUMBER</strong> from the text for each answer.</p>
<p class="MsoNormal" style="text-align: center;" align="center"><strong><span style="font-size: 14.0pt; line-height: 115%;">Applying for jobs online</span></strong></p>
<p class="MsoNormal">Select a job you like in the {Current Vacancies} section.<br>• Read the job description and click Apply Now.</p>
<p class="MsoNormal">Sign up for a new account in the section named {First Time Applicant} .<br>• Accept the terms of the data collection policy.</p>
<p class="MsoNormal">Work on your application form. You can move between tabs, and this allows you to fill in {sections|small sections} of the application form, completing one at a time.</p>
<p class="MsoNormal">When you’re satisfied with your application, click the Complete tab, and then click Submit after putting in your {name} .</p>
<p class="MsoNormal">You do not have to finish your application in {one sitting |1 sitting} . You can have a break and then go into My Applications to continue working on applications currently in progress there.</p>
<p class="MsoNormal">NB If you are applying for multiple posts, the {recruitment office} will need a separate application for each post.</p>
<p class="MsoNormal"> </p>', NULL, 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">22. Đáp án: {Current Vacancies}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Once you’ve found a post in the <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"44\">Current Vacancies</strong> that you’d like to apply for…”</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">23. Đáp án: {First Time Applicant}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Scroll down the section that says <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"46\">First Time Applicant</strong> to enter your email address…”</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">24. Đáp án: {sections}</strong> hoặc <strong data-path-to-node=\"24\" data-index-in-node=\"28\">{small sections}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “These are split up to enable you to work on <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"56\">small sections</strong> of the application at any one time.”</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">25. Đáp án: {name}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “When you have finished, click the Complete tab. You then <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"69\">type your name (this is instead of a signature)</strong> and click Submit.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bạn điền tên của mình thay cho chữ ký trước khi nhấn gửi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">26. Đáp án: {one sitting}</strong> hoặc <strong data-path-to-node=\"28\" data-index-in-node=\"31\">{1 sitting}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The application does not need to be completed in <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"61\">one sitting</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “one sitting” nghĩa là làm một lèo từ đầu đến cuối mà không nghỉ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">27. Đáp án: {recruitment office}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “You will need to submit an application form to the <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"63\">recruitment office</strong> for every position…”</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('ca2e7a95-dac9-4aa7-aa32-91bca2548a7d', '2613bfbc-f9d6-4cdf-a469-5bd5c687e988', 'matrix', 'Questions 28–34', '', '<p data-start="137" data-end="176">Which paragraph mentions the following?</p>
<p data-start="178" data-end="245">Write the correct letter, <strong>A</strong>–<strong>I</strong>, in boxes 28–34 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a comparison between new and traditional turbine designs", "correctCategoryLetter": "C"}, {"itemText": "two unsatisfactory attempts to include wind turbines in buildings", "correctCategoryLetter": "F"}, {"itemText": "an official policy relating to energy production", "correctCategoryLetter": "B"}, {"itemText": "disappointing modifications to plans for an innovative corporate building", "correctCategoryLetter": "H"}, {"itemText": "a claim that changes in building design will impact the way urban areas look", "correctCategoryLetter": "I"}, {"itemText": "wind farms in urban areas as one solution to the problem of appearance", "correctCategoryLetter": "E"}, {"itemText": "a source of finance for the development of a new turbine for an offshore project", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">28. Đáp án: {C}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “While <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"18\">conventional turbines</strong> rotate on a horizontal axis… the tall, V-shaped <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"90\">Aerogenerator</strong> spins on a vertical axis…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C so sánh trực tiếp cấu tạo của turbine truyền thống (trục ngang) và thiết kế Aerogenerator mới (trục đứng).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">29. Đáp án: {F}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Nhắc đến dự án của <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"30\">Richard Rogers</strong> (bị từ chối) và <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"61\">William Pedersen</strong> (không đáp ứng được nhu cầu năng lượng thực tế).</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là hai nỗ lực đưa turbine vào tòa nhà nhưng không thành công hoặc không thỏa đáng (unsatisfactory attempts).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">30. Đáp án: {B}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…in an effort to meet the <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"40\">government’s interim target</strong> for renewable-sourced energy…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Interim target” (mục tiêu tạm thời) của chính phủ chính là một chính sách chính thức (official policy) về sản xuất năng lượng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">31. Đáp án: {H}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"19\">Freedom Tower</strong>… instead of a powerful advertisement for wind power’s potential… became a <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"111\">rather ordinary office block</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc thay đổi thiết kế từ một “urban wind farm” đột phá thành một tòa nhà văn phòng bình thường là một sự sửa đổi gây thất vọng (disappointing modifications).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">32. Đáp án: {I}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “‘…It’s a whole different layer of architecture coming through that will begin to <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"95\">change the face of our cities</strong>,’ says Battle.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Guy Battle khẳng định những thay đổi trong thiết kế công trình sẽ làm thay đổi diện mạo (change the face/impact the way look) của các khu đô thị.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">33. Đáp án: {E}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…why not put them in the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"39\">cities</strong>? Cities already have high-rise structures… would be <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"100\">in tune with a man-made environment</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc đặt turbine ở thành phố giúp giải quyết vấn đề thẩm mỹ (appearance) vì chúng hòa hợp với môi trường nhân tạo thay vì làm hỏng cảnh quan nông thôn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">34. Đáp án: {D}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…funding this new Aerogenerator project… through a combination of a <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"84\">government grant and the money he was saving to buy a new house</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nguồn tài chính đến từ trợ cấp chính phủ và tiền tiết kiệm cá nhân của Theo Bird.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d123913e-12a7-46ad-bcf8-8028760f53ea', '2613bfbc-f9d6-4cdf-a469-5bd5c687e988', 'matrix', 'Questions 35–40', '', '<p data-start="154" data-end="202">Match each project with the correct person, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="204" data-end="271">Write the correct letter, <strong>A</strong>–<strong>E</strong>, in boxes 35–40 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "an ambitious design which resulted in a boring building", "correctCategoryLetter": "E"}, {"itemText": "a venture partially financed by personal wealth", "correctCategoryLetter": "A"}, {"itemText": "a building designed for leisure activities", "correctCategoryLetter": "C"}, {"itemText": "a design for a building capable of producing virtually all its own energy", "correctCategoryLetter": "D"}, {"itemText": "a project supported by a group of countries", "correctCategoryLetter": "D"}, {"itemText": "a structure that may make use of more than one natural energy source", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Theo Bird", "categoryLetter": "A"}, {"categoryText": "Richard Rogers", "categoryLetter": "B"}, {"categoryText": "William Pedersen", "categoryLetter": "C"}, {"categoryText": "Sinisa Stankovic", "categoryLetter": "D"}, {"categoryText": "Guy Battle", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">35. Đáp án: {E} Guy Battle</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Guy Battle là kỹ sư tư vấn cho <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"42\">Freedom Tower</strong> – dự án vốn rất tham vọng nhưng cuối cùng lại thành một tòa nhà văn phòng tẻ nhạt (boring building). (Đoạn H)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">36. Đáp án: {A} Theo Bird</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"19\">money he was saving to buy a new house</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Anh ấy dùng tiền cá nhân của mình (personal wealth) để đầu tư vào dự án Aerogenerator.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">37. Đáp án: {C} William Pedersen</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…William Pedersen’s <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"34\">sports centre</strong> in New York…” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Sports centre” (trung tâm thể thao) là một tòa nhà phục vụ các hoạt động giải trí/thể thao (leisure activities).</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">38. Đáp án: {D} Sinisa Stankovic</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…According to… Sinisa Stankovic, under the right circumstances such a building could <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"101\">generate nearly all of its own energy needs</strong>.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Nearly all” tương ứng với “virtually all” (hầu như toàn bộ).</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">39. Đáp án: {D} Sinisa Stankovic</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"17\">European Commission-sponsored</strong> organisation named Project WEB…” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> European Commission (Ủy ban Châu Âu) đại diện cho một nhóm các quốc gia. Dự án này do Sinisa Stankovic làm kỹ sư môi trường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">40. Đáp án: {A} Theo Bird</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…double the power from each turbine by harnessing <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"64\">tidal power</strong> [alongside wind power].” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thiết kế của Theo Bird có tiềm năng kết hợp cả năng lượng gió và năng lượng thủy triều (more than one natural energy source).</p>\n</li>\n</ul>\n<div class=\"attachment-container search-images\"> </div>"}]', 1);
INSERT INTO public.questions VALUES ('1f8776c2-13ee-49e7-876b-eac5ea387fae', '2f851700-0342-4d61-bede-f0fafb1c4f63', 'matrix', 'Questions 1–7', '', '<p data-start="156" data-end="208">For which gym bag are the following statements true?</p>
<p data-start="210" data-end="283">Write the correct letter, <strong data-start="236" data-end="243">A–F</strong>, in boxes <strong data-start="254" data-end="261">1–7</strong> on your answer sheet.</p>
<p data-start="285" data-end="330"> </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Owners of this bag can put wet swimwear in it and keep other items dry", "correctCategoryLetter": "F"}, {"itemText": "This bag will not wear out quickly", "correctCategoryLetter": "B"}, {"itemText": "If someone is looking for an environmentally friendly bag, this one would be appropriate", "correctCategoryLetter": "A"}, {"itemText": "People can choose from two different sizes of this bag", "correctCategoryLetter": "E"}, {"itemText": "This bag would suit someone who does not want to spend too much", "correctCategoryLetter": "F"}, {"itemText": "This bag has only just appeared on the market", "correctCategoryLetter": "A"}, {"itemText": "This bag weighs more than some other gym bags", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">1. Owners of this bag can put wet swimwear in it and keep other items dry.</strong> <em data-path-to-node=\"3\" data-index-in-node=\"75\">(Người sở hữu túi này có thể để đồ bơi ướt vào trong mà vẫn giữ các đồ khác khô ráo.)</em></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {F} Under Armour sports style duffel</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a separate smaller <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"34\">waterproof compartment</strong> at one of the ends is ideal for putting <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"97\">damp gear</strong> in so that everything else is <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"137\">unaffected</strong> by it.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Damp gear” (đồ ẩm/ướt) tương ứng với “wet swimwear”. Ngăn chống thấm riêng biệt (waterproof compartment) giúp đồ đạc khác không bị ảnh hưởng (unaffected).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. This bag will not wear out quickly.</strong> <em data-path-to-node=\"5\" data-index-in-node=\"39\">(Chiếc túi này sẽ không bị hỏng/mòn nhanh chóng.)</em></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: {B} Filson medium rugged twill duffel bag</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “If you’re inclined to treat yourself to a bag that should <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"70\">last you a lifetime</strong>, this is for you.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một chiếc túi có thể dùng “cả đời” (last a lifetime) đồng nghĩa với việc nó rất bền và không dễ bị hỏng (will not wear out quickly).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">3. If someone is looking for an environmentally friendly bag, this one would be appropriate.</strong> <em data-path-to-node=\"7\" data-index-in-node=\"93\">(Nếu ai đó tìm kiếm một chiếc túi thân thiện với môi trường, chiếc này sẽ phù hợp.)</em></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: {A} Fjällräven Vardag Duffel 30</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it’s also great from an <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"39\">eco-perspective</strong>, as it’s made from 65 per cent <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"86\">recycled</strong> polyester and 35 per cent <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"121\">organic</strong> cotton.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các từ khóa “eco-perspective” (góc độ sinh thái), “recycled” (tái chế) và “organic” (hữu cơ) khẳng định tính thân thiện với môi trường của túi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">4. People can choose from two different sizes of this bag.</strong> <em data-path-to-node=\"9\" data-index-in-node=\"59\">(Mọi người có thể chọn giữa hai kích cỡ khác nhau của loại túi này.)</em></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: {E} The North Face Base Camp Duffel</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This… bag has a very generous <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"44\">50 litre</strong> storage capacity. If that’s too much for you, there’s always the trimmer <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"126\">31 litre</strong> equivalent…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đưa ra hai lựa chọn dung tích là 50 lít và 31 lít.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">5. This bag would suit someone who does not want to spend too much.</strong> <em data-path-to-node=\"11\" data-index-in-node=\"68\">(Chiếc túi này phù hợp với người không muốn chi tiêu quá nhiều.)</em></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: {F} Under Armour sports style duffel</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It’s a decent option for an everyday gym bag that <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"62\">won’t break the bank</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thành ngữ “won’t break the bank” nghĩa là chi phí rẻ, không tốn quá nhiều tiền.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">6. This bag has only just appeared on the market.</strong> <em data-path-to-node=\"13\" data-index-in-node=\"50\">(Chiếc túi này chỉ vừa mới xuất hiện trên thị trường.)</em></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: {A} Fjällräven Vardag Duffel 30</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This premium outdoor brand has a <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"45\">newly released</strong> lightweight bag in its product range.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Newly released” (vừa mới phát hành) đồng nghĩa với việc nó vừa mới xuất hiện trên thị trường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">7. This bag weighs more than some other gym bags.</strong> <em data-path-to-node=\"15\" data-index-in-node=\"50\">(Chiếc túi này nặng hơn một số túi tập gym khác.)</em></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: {C} Deuter Trans Alpine Pro 28</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This pack has got so many features, which does, however, make it on the <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"84\">heavier side</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “on the heavier side” xác nhận chiếc túi này thuộc loại nặng hơn so với thông thường.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e8ab4d83-de06-40ea-87aa-c009fd6eaf94', '2f851700-0342-4d61-bede-f0fafb1c4f63', 'radio', 'Questions 8–14', '', '<p data-start="2049" data-end="2160">Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The coasteering centre guarantees participants will see animals in the sea during their session"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Participants need to walk from the centre in Croyde to the start of their coasteering session"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Refreshments in the café are included in the fee for the course"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The thrill-seeker route is the most popular one"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Participants need to pay extra to hire the necessary items of safety equipment"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The centre recommends participants put on a particular type of footwear"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It is possible to combine coasteering with learning another sport"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">8. The coasteering centre guarantees participants will see animals in the sea during their session.</strong> <em data-path-to-node=\"3\" data-index-in-node=\"100\">(Trung tâm coasteering đảm bảo người tham gia sẽ thấy động vật dưới biển trong suốt buổi tập.)</em></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {FALSE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…on some days you <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"32\">may even be able to</strong> observe a variety of marine wildlife.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói bạn “có thể” (may) thấy động vật vào “một số ngày”, trong khi câu hỏi dùng từ “guarantees” (đảm bảo). Đây là thông tin trái ngược về mức độ chắc chắn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">9. Participants need to walk from the centre in Croyde to the start of their coasteering session.</strong> <em data-path-to-node=\"5\" data-index-in-node=\"98\">(Người tham gia cần đi bộ từ trung tâm ở Croyde đến điểm bắt đầu buổi coasteering.)</em></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: {FALSE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “From our centre you’re <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"35\">transported</strong> to the coasteering location on Baggy Point.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Người tham gia được “vận chuyển/chở đi” (transported) chứ không phải tự đi bộ (walk).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">10. Refreshments in the café are included in the fee for the course.</strong> <em data-path-to-node=\"7\" data-index-in-node=\"69\">(Đồ uống/đồ ăn nhẹ tại quán cà phê đã bao gồm trong học phí.)</em></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: {NOT GIVEN}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…you can also get a drink or snack in the café.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói có quán cà phê để bạn có thể mua đồ uống/đồ nhẹ, nhưng <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"83\">không hề đề cập</strong> việc nó có miễn phí hay đã bao gồm trong phí £40 hay chưa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">11. The thrill-seeker route is the most popular one.</strong> <em data-path-to-node=\"9\" data-index-in-node=\"53\">(Lộ trình “thrill-seeker” là lộ trình phổ biến nhất.)</em></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: {NOT GIVEN}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Then there is the adventurer challenge and the more challenging thrill-seeker route.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có liệt kê tên các lộ trình nhưng <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"54\">không có thông tin</strong> so sánh lộ trình nào “phổ biến nhất” (most popular).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">12. Participants need to pay extra to hire the necessary items of safety equipment.</strong> <em data-path-to-node=\"11\" data-index-in-node=\"84\">(Người tham gia cần trả thêm tiền để thuê các vật dụng thiết bị an toàn cần thiết.)</em></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: {FALSE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Sessions are £40 per person, which <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"47\">covers the use of</strong> wetsuits, helmets and buoyancy aid…” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Phí £40 đã “bao gồm” (covers) việc sử dụng thiết bị (mũ bảo hiểm, áo phao), nên việc nói phải “trả thêm” (pay extra) là sai. <em data-path-to-node=\"12,2,0\" data-index-in-node=\"137\">Lưu ý: Chỉ có khăn tắm (towels) mới phải trả phí nhỏ để thuê.</em></p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">13. The centre recommends participants put on a particular type of footwear.</strong> <em data-path-to-node=\"13\" data-index-in-node=\"77\">(Trung tâm khuyến nghị người tham gia mang một loại giày dép cụ thể.)</em></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: {TRUE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and a pair of <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"29\">trainers</strong> to help you grip on slippery surfaces.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Footwear” (giày dép) ở đây chính là “trainers” (giày thể thao) mà trung tâm yêu cầu người tham gia mang theo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">14. It is possible to combine coasteering with learning another sport.</strong> <em data-path-to-node=\"15\" data-index-in-node=\"71\">(Có thể kết hợp coasteering với việc học một môn thể thao khác.)</em></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: {TRUE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “If you’re also interested in <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"41\">surfing</strong>, you can <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"58\">add lessons</strong> to your coasteering sessions…” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Another sport” ở đây chính là môn lướt sóng (surfing). Việc “add lessons” (thêm các buổi học) chính là sự kết hợp (combine).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('1ee3587b-a733-4475-9e9f-6115faef6899', '5e03fc9f-f2d7-46f6-932c-e7dae48bfc20', 'checkbox', 'Question 17-18', NULL, '<p>Choose <strong>TWO </strong>letters, A–E.</p>
<p>Which TWO things does Heather explain about kilns?</p>', 'multiple_choice_many', 'null', '[{"option": "A. what their function is", "correct": false}, {"option": "B. when they were invented", "correct": false}, {"option": "C. ways of keeping them safe", "correct": true}, {"option": "D. where to put one in your home", "correct": false}, {"option": "E. what some people use instead of one", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('cb6b555a-f893-4f3a-b6a9-437676d7ce4d', '6a9db81e-87b7-48f4-aa1d-5ab8b8f84742', 'fillup', 'Questions 15–21', '<p data-start="100" data-end="125">Complete the notes below.</p>
<p data-start="127" data-end="182">Choose <strong data-start="134" data-end="151">ONE WORD ONLY</strong> from the text for each answer.</p>
<table style="border-collapse: collapse; width: 100.028%;" border="1"><colgroup> <col style="width: 100%;"></colgroup>
<tbody>
<tr>
<td>
<p style="text-align: center;" data-start="246" data-end="285"><span style="font-size: 14pt;"><strong data-start="249" data-end="285">How to become a freelance writer</strong></span></p>
<p data-start="287" data-end="359">Freelancing gives would-be writers a chance to get some paid experience.</p>
<p data-start="361" data-end="384"><strong data-start="365" data-end="384">Sources of work</strong></p>
<p data-start="386" data-end="410"><strong data-start="386" data-end="410">specialist websites:</strong></p>
<ul data-start="411" data-end="505">
<li data-start="411" data-end="505">
<p data-start="413" data-end="505">best to check out that potential employers are <strong data-start="460" data-end="474">{genuine}</strong> before agreeing to do any work</p>
</li>
</ul>
<p data-start="507" data-end="521"><strong data-start="507" data-end="521">the press:</strong></p>
<ul data-start="522" data-end="593">
<li data-start="522" data-end="593">
<p data-start="524" data-end="593">ensure all <strong data-start="535" data-end="549">{pitches}</strong> are persuasive and kept to a minimum length</p>
</li>
</ul>
<p data-start="600" data-end="639"><strong data-start="604" data-end="639">Advantages of freelance writing</strong></p>
<ul data-start="641" data-end="816">
<li data-start="641" data-end="696">
<p data-start="643" data-end="696">the power to decide on the size of the <strong data-start="682" data-end="696">{workload}</strong></p>
</li>
<li data-start="697" data-end="747">
<p data-start="699" data-end="747">the <strong data-start="703" data-end="717">{flexibility}</strong> in the scheduling of the work</p>
</li>
<li data-start="748" data-end="816">
<p data-start="750" data-end="816">the chance to commit to a second <strong data-start="783" data-end="797">{job}</strong> to generate income</p>
</li>
</ul>
<p data-start="823" data-end="865"><strong data-start="827" data-end="865">Disadvantages of freelance writing</strong></p>
<ul data-start="867" data-end="1111">
<li data-start="867" data-end="975">
<p data-start="869" data-end="975">it is largely expected that young freelancers will be happy to complete assignments without <strong data-start="961" data-end="975">{payment}</strong></p>
</li>
<li data-start="976" data-end="1040">
<p data-start="978" data-end="1040">graduates whose <strong data-start="994" data-end="1008">{motivation}</strong> is limited may not get any work</p>
</li>
<li data-start="1041" data-end="1111">
<p data-start="1043" data-end="1111">it may be hard trying to live without money coming in at fixed times</p>
</li>
</ul>
</td>
</tr>
</tbody>
</table>
<p> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">15. best to check out that potential employers are {genuine} before agreeing to do any work</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “These sites can be useful but just make sure any organisation is </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"77\">genuine</strong><span class=\"\"> first.</span><span class=\"\">” (Đoạn 3)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Potential employers” tương ứng với “any organisation”.</span><span class=\"\"> Bạn cần kiểm tra xem họ có </span><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"95\">thật sự uy tín/chính thống</strong><span class=\"\"> (genuine) không để tránh làm việc mà không được trả tiền.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">16. ensure all {pitches} are persuasive and kept to a minimum length</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">keep the </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"24\">pitches</strong><span class=\"\"> – in which you present what you could write for them – brief and interesting.</span><span class=\"\">” (Đoạn 4)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Persuasive” (có tính thuyết phục) tương ứng với “interesting”,</span><span class=\"\"> và “minimum length” (độ dài tối thiểu/ngắn gọn) tương ứng với “brief”.</span><span class=\"\"> Đối tượng cần giữ ngắn gọn ở đây là các </span><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"187\">bài chào hàng/ý tưởng viết</strong><span class=\"\"> (pitches).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">17. the power to decide on the size of the {workload}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">having the responsibility of determining your own </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"65\">workload</strong><span class=\"\">.</span><span class=\"\">” (Đoạn 5)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “The power to decide” (quyền quyết định) đồng nghĩa với “responsibility of determining”.</span><span class=\"\"> Người viết tự quyết định khối lượng </span><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"137\">công việc</strong><span class=\"\"> (workload) của mình.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">18. the {flexibility} in the scheduling of the work</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">and of course the </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"33\">flexibility</strong><span class=\"\"> of the work hours may suit you.</span><span class=\"\">” (Đoạn 5)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Scheduling of the work” (sắp xếp thời gian làm việc) tương ứng với “work hours”.</span><span class=\"\"> Ưu điểm lớn nhất ở đây là sự </span><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"123\">linh hoạt</strong><span class=\"\"> (flexibility).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">19. the chance to commit to a second {job} to generate income</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">it also leaves it open for you to get a part-time </span><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"65\">job</strong><span class=\"\">,</span><span class=\"\"> however basic,</span><span class=\"\"> which would bring in a regular amount.</span><span class=\"\">” (Đoạn 5)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Freelance cho phép bạn làm thêm một công việc thứ hai (thường là bán thời gian) để có thu nhập ổn định.</span><span class=\"\"> Từ cần điền là </span><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"131\">job</strong><span class=\"\">.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"0\">20. it is largely expected that young freelancers will be happy to complete assignments without {payment}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong class=\"\" data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Graduate writers are notorious for working for no actual </span><strong class=\"\" data-path-to-node=\"14,0,0\" data-index-in-node=\"69\">payment</strong><span class=\"\">…</span><span class=\"\">” (Đoạn 6)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong class=\"\" data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Young freelancers” tương ứng với “Graduate writers”.</span><span class=\"\"> Các công ty thường mặc định rằng sinh viên mới tốt nghiệp sẵn sàng làm việc mà không cần </span><strong class=\"\" data-path-to-node=\"14,1,0\" data-index-in-node=\"155\">trả lương/thanh toán</strong><span class=\"\"> (payment).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"0\">21. graduates whose {motivation} is limited may not get any work</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong class=\"\" data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Freelancing is probably not for people who lack </span><strong class=\"\" data-path-to-node=\"16,0,0\" data-index-in-node=\"60\">motivation</strong><span class=\"\">.</span><span class=\"\">” (Đoạn 7)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong class=\"\" data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Limited” đồng nghĩa với “lack” (thiếu/hạn chế).</span> Nếu thiếu <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"71\">động lực</strong> (motivation), công việc sẽ không tự tìm đến bạn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('5da3a7ad-72d8-4a5f-8b3b-299f0309400a', '6a9db81e-87b7-48f4-aa1d-5ab8b8f84742', 'fillup', 'Questions 22–27', '<p data-start="87" data-end="116">Complete the sentences below.</p>
<p data-start="118" data-end="173">Choose <strong data-start="125" data-end="142">ONE WORD ONLY</strong> from the text for each answer.</p>
<p data-start="236" data-end="321">The writer should make sure that they have separated the CV into suitable <strong data-start="310" data-end="320">{sections}</strong>.</p>
<p data-start="327" data-end="422">If the text of a CV is too long, there is a risk that the reader’s <strong data-start="394" data-end="404">{interest}</strong> will not be held.</p>
<p data-start="428" data-end="514">It is advisable to highlight the essential <strong data-start="471" data-end="481">{skills}</strong> for the post early on in the CV.</p>
<p data-start="520" data-end="643">Writers should support statements in their CV with facts, for example how big is the <strong data-start="605" data-end="615">{budget}</strong> that they are in charge of.</p>
<p data-start="649" data-end="738">It is worth giving details of any past <strong data-start="688" data-end="698">{achievements}</strong>, together with any relevant statistics.</p>
<p data-start="744" data-end="819">Checking that no <strong data-start="761" data-end="771">{mistakes}</strong> appear in the language used in the CV is vital.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">22. The writer should make sure that they have separated the CV into suitable {sections}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…make sure your CV is extremely easy to read and is divided into appropriate <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"91\">sections</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “separated” (phân tách) đồng nghĩa với “divided” (chia nhỏ). Người viết cần đảm bảo CV được chia thành các <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"122\">phần</strong> (sections) phù hợp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">23. If the text of a CV is too long, there is a risk that the reader’s {interest} will not be held.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Never make readers wade through large amounts of writing or you will risk losing their <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"99\">interest</strong> quickly.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Text… too long” tương ứng với “large amounts of writing”. Nếu viết quá dài, bạn sẽ có nguy cơ làm mất đi sự <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"123\">hứng thú</strong> (interest) của người đọc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">24. It is advisable to highlight the essential {skills} for the post early on in the CV.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…identify what <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"29\">skills</strong> are most needed and ensure these are clearly included near the beginning of your CV.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Essential” (thiết yếu) tương ứng với “most needed”. “Early on” (ngay từ đầu) tương ứng với “near the beginning”. Những <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"132\">kỹ năng</strong> quan trọng cần được làm nổi bật ở phần đầu CV.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">25. Writers should support statements in their CV with facts, for example how big is the {budget} that they are in charge of.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Demonstrate the scale of your responsibilities by including numbers such as the size of <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"100\">budget</strong> you control…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Support statements… with facts” tương ứng với “back them up with facts”. Việc “in charge of” (chịu trách nhiệm) đồng nghĩa với “control”. Ví dụ cụ thể ở đây là quy mô của <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"186\">ngân sách</strong> (budget).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">26. It is worth giving details of any past {achievements}, together with any relevant statistics.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “You can also prove your impact by including quantifiable <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"69\">achievements</strong> you have had.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Relevant statistics” (số liệu thống kê liên quan) tương ứng với “quantifiable” (có thể định lượng). Người viết nên đưa ra các chi tiết về những <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"157\">thành tựu</strong> (achievements) trong quá khứ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">27. Checking that no {mistakes} appear in the language used in the CV is vital.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Obvious spelling and grammar <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"41\">mistakes</strong> will be warning signs…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc kiểm tra ngôn ngữ trong CV là cực kỳ quan trọng (vital) để đảm bảo không có các <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"97\">lỗi</strong> (mistakes) về chính tả hay ngữ pháp.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b0fcae99-fc47-4aa2-8232-4c92a1ae51c4', '31da2791-51ab-4428-a0b2-4acbf4bfe9a2', 'matching', 'Questions 28–33', '', '<p data-start="245" data-end="321">Choose the correct heading for each section from the list of headings below.</p>
<p data-start="323" data-end="397">Write the correct number, <strong data-start="349" data-end="359">i–viii</strong>, in boxes 28–33 on your answer sheet.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i Defences which proved inadequate"}, {"optionText": "ii Why Tushan’s governors were so important"}, {"optionText": "iii An approaching force of a different type"}, {"optionText": "iv A detailed description of one building on the site"}, {"optionText": "v An important link in the chain of defences"}, {"optionText": "vi How domestic buildings in the lower town were furnished"}, {"optionText": "vii The main reason for the archaeological investigations"}, {"optionText": "viii Where the trade deals were done"}], "matchingItems": []}', 'null', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">28. Section A: {vii} The main reason for the archaeological investigations</strong></p>\n<ul data-path-to-node=\"4,0,1\">\n<li>\n<p data-path-to-node=\"4,0,1,0,0\"><strong data-path-to-node=\"4,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The dam… will flood up to 500 archaeological sites. However, its construction has also provided a <strong data-path-to-node=\"4,0,1,0,0\" data-index-in-node=\"112\">great opportunity to learn about the past</strong>… the government invited teams… to recover as much as they could.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,0,1,1,0\"><strong data-path-to-node=\"4,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý do chính của cuộc điều tra là việc xây đập Ilisu sẽ làm ngập các di tích, tạo ra cơ hội “cứu vãn” khảo cổ.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">29. Section B: {v} An important link in the chain of defences</strong></p>\n<ul data-path-to-node=\"4,1,1\">\n<li>\n<p data-path-to-node=\"4,1,1,0,0\"><strong data-path-to-node=\"4,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tušhan was a provincial centre which <strong data-path-to-node=\"4,1,1,0,0\" data-index-in-node=\"49\">guarded the northern border</strong> of the mighty Assyrian Empire…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,1,1,0\"><strong data-path-to-node=\"4,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thành phố này đóng vai trò như một chốt chặn bảo vệ biên giới phía Bắc, là một mắt xích trong hệ thống phòng thủ.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">30. Section C: {iv} A detailed description of one building on the site</strong></p>\n<ul data-path-to-node=\"4,2,1\">\n<li>\n<p data-path-to-node=\"4,2,1,0,0\"><strong data-path-to-node=\"4,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Cả đoạn này mô tả chi tiết về <strong data-path-to-node=\"4,2,1,0,0\" data-index-in-node=\"41\">Governor’s palace</strong> (Cung điện thống đốc): từ vị trí, King Ashurnasirpal II, trang trí tường (geometric patterns), đến hệ thống sưởi và phòng tắm.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"4,3,0\"><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">31. Section D: {viii} Where the trade deals were done</strong></p>\n<ul data-path-to-node=\"4,3,1\">\n<li>\n<p data-path-to-node=\"4,3,1,0,0\"><strong data-path-to-node=\"4,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This building was the <strong data-path-to-node=\"4,3,1,0,0\" data-index-in-node=\"34\">commercial and administrative centre</strong> of Tušhan.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,3,1,1,0\"><strong data-path-to-node=\"4,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về “lower town” nơi diễn ra các hoạt động thương mại, trao đổi hàng hóa và lưu trữ hồ sơ.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"4,4,0\"><strong data-path-to-node=\"4,4,0\" data-index-in-node=\"0\">32. Section E: {i} Defences which proved inadequate</strong></p>\n<ul data-path-to-node=\"4,4,1\">\n<li>\n<p data-path-to-node=\"4,4,1,0,0\"><strong data-path-to-node=\"4,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…massive fortifications… city wall… almost three metres thick… <strong data-path-to-node=\"4,4,1,0,0\" data-index-in-node=\"83\">Despite these precautions, Tušhan fell</strong> with the rest of the Assyrian Empire.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,4,1,1,0\"><strong data-path-to-node=\"4,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dù có tường thành kiên cố nhưng Tušhan vẫn thất thủ trước quân Medes và Babylonians (phòng thủ không đủ/không tương xứng).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"4,5,0\"><strong data-path-to-node=\"4,5,0\" data-index-in-node=\"0\">33. Section F: {iii} An approaching force of a different type</strong></p>\n<ul data-path-to-node=\"4,5,1\">\n<li>\n<p data-path-to-node=\"4,5,1,0,0\"><strong data-path-to-node=\"4,5,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Now Tušhan faces <strong data-path-to-node=\"4,5,1,0,0\" data-index-in-node=\"29\">another threat</strong>, as the <strong data-path-to-node=\"4,5,1,0,0\" data-index-in-node=\"52\">water</strong> from the Ilisu Dam advances…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,5,1,1,0\"><strong data-path-to-node=\"4,5,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Lực lượng” đang tiến đến lần này không phải là quân đội mà là dòng nước lũ từ con đập.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c2883b2a-917e-41e5-9ecf-5f0d7b0e02fa', '31da2791-51ab-4428-a0b2-4acbf4bfe9a2', 'fillup', 'Questions 34–37', '<p data-start="103" data-end="130">Complete the summary below.</p>
<p data-start="132" data-end="204">Choose <strong data-start="139" data-end="156">ONE WORD ONLY</strong> from <strong data-start="162" data-end="175">Section D</strong> of the text for each answer.</p>
<table style="border-collapse: collapse; width: 99.9971%; height: 305.725px;" border="1"><colgroup> <col style="width: 99.8607%;"></colgroup>
<tbody>
<tr style="height: 305.725px;">
<td>
<p style="text-align: center;" data-start="272" data-end="299"><span style="font-size: 14pt;"><strong data-start="276" data-end="299">Tušhan’s lower town</strong></span></p>
<p data-start="301" data-end="543">Below the mound where the governor’s palace stood was a large lower town.<br data-start="374" data-end="377">Archaeologists found some houses of considerable size there, which had spacious courtyards in the middle. These had attractive patterned <strong data-start="514" data-end="528">{mosaics}</strong> on the floors.</p>
<p data-start="545" data-end="897">Archaeologists discovered a large number of differently shaped artefacts in one of the buildings. They discovered a large number of very small <strong data-start="688" data-end="702">{tokens}</strong>, which represented a variety of goods and quantities. They were probably adopted by the townspeople to maintain <strong data-start="815" data-end="829">{records}</strong> of goods, as well as men and women, that entered and left the town.</p>
<p data-start="899" data-end="1122">Later, a number of inscribed tablets were discovered, which mostly recorded the transport of <strong data-start="992" data-end="1006">{barley}</strong>. This trade was also evident in the remains of some enormous jars that were found, which had been used for storage.</p>
</td>
</tr>
</tbody>
</table>
<p> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('b56cac84-afc0-4760-ba0e-2e028e06ce03', '31da2791-51ab-4428-a0b2-4acbf4bfe9a2', 'radio', 'Questions 38–40', '', '<p data-start="103" data-end="147">Choose the correct letter, <strong data-start="130" data-end="146">A, B, C or D</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A It was built in an area which the Assyrians had taken over"}, {"option_text": "B It was an impressive city the same size as Nineveh"}, {"option_text": "C It was situated in the middle of the northern region of Assyria"}, {"option_text": "D It was inhabited mainly by Assyrian soldiers and their families"}], "question": "What do we learn about the ancient city of Tušhan?"}, {"correct": 1, "options": [{"option_text": "A Assyrian cremations did not generally include any bronze bowls"}, {"option_text": "B They indicate that some governors may have been foreigners"}, {"option_text": "C The furniture that was found there was unusual for the period"}, {"option_text": "D They were the only bodies that were excavated in Tušhan"}], "question": "Why do archaeologists consider the burials under the palace significant?"}, {"correct": 3, "options": [{"option_text": "A It is clear that Tušhan will soon be completely under water"}, {"option_text": "B Everything is now known about the history of the Tušhan area"}, {"option_text": "C Other cities will be researched through the Ziyaret Tepe project"}, {"option_text": "D It is likely that documents will be the only source of information on Tušhan"}], "question": "In Section F, what conclusion does the writer come to?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">38. What do we learn about the ancient city of Tušhan? — {A} It was built in an area which the Assyrians had taken over.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…part of the Assyrian network of imperial control which imposed authority over <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"93\">conquered regions</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thành phố này nằm trong vùng đất bị chinh phục (conquered regions), tức là vùng đất người Assyria đã đánh chiếm/tiếp quản.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><em data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Loại B vì bài nói nó “never approached the grandeur” (không bao giờ hùng vĩ bằng) Nineveh.</em></p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">39. Why do archaeologists consider the burials under the palace significant? — {B} They indicate that some governors may have been foreigners.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…cremation was <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"29\">not an Assyrian practice</strong> and these burials suggest that Tušhan’s ruling elite… were <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"115\">not themselves Assyrians</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc hỏa táng không phải là tập tục của người Assyria, cho thấy tầng lớp cai trị (thống đốc) có thể là người địa phương hoặc người nước ngoài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">40. In Section F, what conclusion does the writer come to? — {D} It is likely that documents will be the only source of information on Tušhan.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…even though its <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"31\">physical remains may be lost</strong>… a rich record… is now preserved in the <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"104\">archives and publications</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi di tích vật lý bị ngập dưới nước và biến mất, các tài liệu lưu trữ và ấn phẩm sẽ trở thành nguồn thông tin duy nhất còn sót lại về Tušhan.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('f18dad4f-3ddf-483b-879a-8bebba019a24', '21ca61c7-0472-4687-8c42-9a7b1647085d', 'checkbox', 'Questions 19–20', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which does the organiser suggest are the <strong>TWO </strong>most popular concert items?</p>
', 'multiple_choice_many', 'null', '[{"option": "A acting", "correct": false}, {"option": "B dancing", "correct": true}, {"option": "C poetry recital", "correct": false}, {"option": "D singing", "correct": true}, {"option": "E storytelling", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('fdb5db40-ce81-429a-a195-7c78278ebbfd', '20b3d9b0-9161-4986-9599-324e831727d0', 'radio', 'Questions 39-40', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "offset bitter flavour in food"}, {"content": "only exist in 304 cup"}, {"content": "tastes like citrus"}, {"content": "chemical reaction when meets biscuit"}], "question": "What is the main feature of AMP according to this passage?"}, {"correct": 3, "options": [{"content": "collecting taste molecule"}, {"content": "identifying different flavors elements"}, {"content": "resolving large molecules"}, {"content": "transmitting bitter signals to the brain"}], "question": "What is the main function of G protein?"}]', 'null', 'null', 'null', '[{"content": "<p><strong class=\"\">39. What is the main feature of AMP according to this passage?</strong></p>\n<p><strong class=\"\">Đáp án:</strong><span class=\"\"> A.</span><span class=\"\"> offset bitter flavour in food</span></p>\n<p><strong class=\"\">Vị trí:</strong><span class=\"\"> Đoạn H,</span><span class=\"\"> dòng 6–10.</span></p>\n<p><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> &#8220;Potassium chloride has a bitter aftertaste,</span><span class=\"\"> but that could be </span><strong class=\"\">eliminated</strong><span class=\"\"> with a dose of AMP&#8230;</span><span class=\"\"> they could </span><strong class=\"\">dampen</strong><span class=\"\"> the bitterness of antihistamines,</span><span class=\"\"> antibiotics&#8230;</span><span class=\"\">&#8220;</span></p>\n<p><strong class=\"\">Giải thích:</strong><span class=\"\"> Trong đoạn H,</span><span class=\"\"> tác giả sử dụng các động từ mạnh như &#8220;eliminated&#8221; (loại bỏ) và &#8220;dampen&#8221; (làm dịu/giảm bớt) để mô tả tác động của AMP đối với vị đắng của muối Kali và các loại thuốc.</span><span class=\"\"> Những hành động này khớp hoàn toàn với ý nghĩa của từ &#8220;offset&#8221; (bù trừ/làm mất đi) trong câu hỏi.</span></p>\n<p><strong>40. What is the main function of G protein?</strong></p>\n<p><strong>Đáp án:</strong> D. transmitting bitter signals to the brain</p>\n<p><strong>Vị trí:</strong> Đoạn E, dòng 8–13.</p>\n<p><strong>Dẫn chứng:</strong> &#8220;Once a bitter signal has been received, it is <strong>relayed via proteins known as G proteins</strong>. [&#8230;] Ultimately, this <strong>delivers a signal to the brain</strong> that registers as bitter.&#8221;</p>\n<p><strong>Giải thích:</strong> Bài đọc mô tả G protein đóng vai trò &#8220;relayed&#8221; (chuyển tiếp) tín hiệu và kết quả là &#8220;delivers a signal to the brain&#8221; (gửi tín hiệu đến não). Hai hành động này chính là chức năng &#8220;transmitting&#8221; (truyền dẫn) tín hiệu vị đắng đến não bộ.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('7e078e9f-b3df-44d2-b646-17c8bd30e906', '806c7a8b-640a-46b5-a83d-a367ba8197f5', 'radio', 'Questions 21-25', '', '<p>Choose the correct letter, <strong>A</strong>,<strong>B </strong>or <strong>C</strong></p>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Song-writing course for drama students</strong></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. listing the references"}, {"option_text": "B. keeping to the word limit"}, {"option_text": "C. writing the evaluation"}], "question": "What problem is Lorna having with her report?"}, {"correct": 2, "options": [{"option_text": "A. to improve hisjob prospects"}, {"option_text": "B. to increase his self-confidence"}, {"option_text": "C. to develop his self-expression"}], "question": "Why did Charles take the song-writing course?"}, {"correct": 2, "options": [{"option_text": "A. individual work"}, {"option_text": "B. pair work"}, {"option_text": "C. group work"}], "question": "Which type of work did Lorna most enjoy?"}, {"correct": 0, "options": [{"option_text": "A. song structure"}, {"option_text": "B. writing a chorus"}, {"option_text": "C. lyrical styles and forms"}], "question": "Which aspect of the course content did both students find interesting?"}, {"correct": 1, "options": [{"option_text": "A. impossible"}, {"option_text": "B. tiring"}, {"option_text": "C. amusing"}], "question": "Lorna found writing a song"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: SONGWRITING COURSE DISCUSSION</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lorna:</strong> Hi Charles. I’m writing my report on the songwriting course for drama students. You know, the one-week residential course for drama students from different universities, where you learn about writing songs. You did that course last year, didn’t you? Could you give me some tips for the report? I’m having a few problems with it.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Charles:</strong> Yes, it was great. Well Lorna, you could start by thinking about what you got out of it.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Lorna:</strong> Hmm, evaluating how useful it was is simple. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"52\">(21) The challenge is not to go over length [Answer: B – word limit]</strong>.</span></p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Charles:</strong> Hmm, referring to published sources might help. That would make it more scholarly too.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Lorna:</strong> OK, I’ll go with that. And saying why you did the songwriting course is important. Some people just do it as another string to their bow, to help with auditions for work and things.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Charles:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"9\">(22) I thought it was a good opportunity to try out new techniques for communicating feelings and emotions [Answer: C – self-expression]</strong>.</span> I was already confident about singing before I did it.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Lorna:</strong> I thought it was the location of the course which made it special—being held in a country house rather than in a university. They were doing some building work on part of the house though, so it wasn’t always easy to concentrate. I enjoyed the workshop most. How about you?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Charles:</strong> Well, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"15\">(23) we were divided into 6 small groups for the afternoon, each with their own advisor. That was the best bit for me [Answer: C – group work]</strong></span>, having that discussion with an expert. When we got into pairs to start writing our songs, the idea was to combine people with different levels of knowledge and experience, but my partner preferred working on her own generally.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Lorna:</strong> Hmm, and what did you think of the course content? <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"58\">(24) I hadn’t realized before how important the structure of a song is to its success.</strong></span><strong data-path-to-node=\"12\" data-index-in-node=\"9\"><span style=\"background-color: #f1c40f;\">[Answer: A – song structure]</span></strong><span style=\"background-color: #f1c40f;\">.</span></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Charles:</strong> <strong data-path-to-node=\"12\" data-index-in-node=\"9\">Yes, we learned it’s no use writing the most beautiful words and melodies if there’s no shape </strong></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Lorna:</strong> Hmm, and we learned about the importance of a chorus in a song. I knew about that stuff from my singing classes. It’s a bit obvious, isn’t it?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Charles:</strong> I suppose so. It was the input on lyrical styles and forms that I found tedious. You could always look them up on the web anyway. How did you get on with writing your song?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Lorna:</strong> It was tough and Peggy, my partner, was hard work, which wasn’t funny, and writing was a slow process as a result of our lack of communication. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"151\">(25) By the time we finished, I was exhausted [Answer: B – tiring]</strong>.</span></p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Charles:</strong> Writing music from the heart is like that, especially by the end of a course.</p>\n<hr data-path-to-node=\"17\">\n<h3 data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">DRAMA WORKSHOPS (Questions 26-30)</strong></h3>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Lorna:</strong> Well, that’s got the report sorted, thanks. Have you decided which teacher’s workshops you’re going to do next term? I want to do Bob Lacey’s. He’s got a brilliant reputation for voice coaching, you know, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"19\" data-index-in-node=\"212\">(26) getting us to use dialects and different pronunciation and stuff [Answer: G – using a range of accents]</strong></span>. He gets you to do things like read out a newspaper article in character. Ha ha, it’s amazing.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Charles:</strong> I’m thinking of going to Evelyn Chance’s workshop.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Lorna:</strong> Oh, Evelyn! She’s quite a character. Is she running the stage fights course again?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Charles:</strong> Yes, fencing and pretend punches and throwing techniques.<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"22\" data-index-in-node=\"67\">(27) She really knows how to help actors use the whole of the space available [Answer: B – full use of the stage]</strong>.</span></p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Lorna:</strong> Lots of people like Ted Winter’s workshop. He knows how to deliver. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"75\">(28) He’s keen on actors conveying emotion through their bodies and faces alone [Answer: D – physical expression]</strong></span>. It’s a great way to reveal complex relationships and situations to an audience without making a speech of any kind. I’m definitely going to sign up for that one.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Charles:</strong> If you want to understand a director’s ideas, Kevin Gray’s workshop would be perfect for you. He likes telling people what to do and he’s always saying you can’t have a company of actors reading a play any way they want because they’d end up fighting amongst themselves. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"24\" data-index-in-node=\"280\">(29) They must listen to the director [Answer: H – following instructions]</strong>.</span></p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Lorna:</strong> What about Dorothy Thomas? <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"34\">(30) She’s good at activities for getting rid of stress and, you know, emptying your mind of all thoughts [Answer: C – relaxation techniques]</strong></span> about the past, and that can really help when acting.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Charles:</strong> Hmm, well, I think I’ll put my name down for…</p>"}]', 0);
INSERT INTO public.questions VALUES ('e523daf9-e32a-4e44-8d1d-b9308ed4b975', 'af935e2f-33ab-4453-9d77-f453b5f73c94', 'matrix', 'Questions 14–18', '', '<p>The text has five paragraphs, <strong>A–E</strong>. Which paragraph contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a description of a company that provides financial assistance for employees to continue their learning", "correctCategoryLetter": "B"}, {"itemText": "a mention of worldwide trends in the changing attitudes of businesses and customers", "correctCategoryLetter": "E"}, {"itemText": "details about years of continuous service by employees at one company", "correctCategoryLetter": "C"}, {"itemText": "a reference to the reason why many people-centered workers first start their own businesses", "correctCategoryLetter": "A"}, {"itemText": "a comment about how certain groups are still fighting for respect in the business world", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-start=\"81\" data-end=\"93\"><strong data-start=\"84\" data-end=\"93\">14. B</strong></p>\n<p data-start=\"95\" data-end=\"132\"><strong data-start=\"95\" data-end=\"106\">Vị trí:</strong> Đoạn B, phần giữa đoạn.</p>\n<p data-start=\"134\" data-end=\"285\"><strong data-start=\"134\" data-end=\"148\">Dẫn chứng:</strong><br data-start=\"148\" data-end=\"151\">“He encourages people to work their way up in the company, and pays, at least partially, for educational opportunities and textbooks.”</p>\n<p data-start=\"287\" data-end=\"502\"><strong data-start=\"287\" data-end=\"302\">Giải thích:</strong><br data-start=\"302\" data-end=\"305\">Công ty Plastic Solutions (Stephen Harper) hỗ trợ tài chính một phần cho nhân viên tiếp tục học tập và mua giáo trình. Đây chính là mô tả về công ty hỗ trợ tài chính cho việc học tập của nhân viên.</p>\n<hr data-start=\"504\" data-end=\"507\">\n<p data-start=\"509\" data-end=\"521\"><strong data-start=\"512\" data-end=\"521\">15. E</strong></p>\n<p data-start=\"523\" data-end=\"566\"><strong data-start=\"523\" data-end=\"534\">Vị trí:</strong> Đoạn E, câu đầu và giữa đoạn.</p>\n<p data-start=\"568\" data-end=\"747\"><strong data-start=\"568\" data-end=\"582\">Dẫn chứng:</strong><br data-start=\"582\" data-end=\"585\">“Family-friendly entrepreneurs are becoming more commonplace internationally…”<br data-start=\"663\" data-end=\"666\">“…parents are important consumers and investors who can change buying practices.”</p>\n<p data-start=\"749\" data-end=\"933\"><strong data-start=\"749\" data-end=\"764\">Giải thích:</strong><br data-start=\"764\" data-end=\"767\">Đoạn E đề cập xu hướng toàn cầu (internationally) và sự thay đổi thái độ của doanh nghiệp và người tiêu dùng (customers/investors). Đây là xu hướng mang tính quốc tế.</p>\n<hr data-start=\"935\" data-end=\"938\">\n<p data-start=\"940\" data-end=\"952\"><strong data-start=\"943\" data-end=\"952\">16. C</strong></p>\n<p data-start=\"954\" data-end=\"985\"><strong data-start=\"954\" data-end=\"965\">Vị trí:</strong> Đoạn C, câu cuối.</p>\n<p data-start=\"987\" data-end=\"1108\"><strong data-start=\"987\" data-end=\"1001\">Dẫn chứng:</strong><br data-start=\"1001\" data-end=\"1004\">“…the company will celebrate six 5-year anniversaries, and one 25-year anniversary among its employees.”</p>\n<p data-start=\"1110\" data-end=\"1259\"><strong data-start=\"1110\" data-end=\"1125\">Giải thích:</strong><br data-start=\"1125\" data-end=\"1128\">Đoạn này nêu rõ số năm làm việc liên tục của nhân viên (5 năm, 25 năm), tức là thông tin về thời gian phục vụ liên tục tại công ty.</p>\n<hr data-start=\"1261\" data-end=\"1264\">\n<p data-start=\"1266\" data-end=\"1278\"><strong data-start=\"1269\" data-end=\"1278\">17. A</strong></p>\n<p data-start=\"1280\" data-end=\"1310\"><strong data-start=\"1280\" data-end=\"1291\">Vị trí:</strong> Đoạn A, câu 2–3.</p>\n<p data-start=\"1312\" data-end=\"1440\"><strong data-start=\"1312\" data-end=\"1326\">Dẫn chứng:</strong><br data-start=\"1326\" data-end=\"1329\">“Many of these go into business themselves as a result of negative experiences they have had in the workplace.”</p>\n<p data-start=\"1442\" data-end=\"1592\"><strong data-start=\"1442\" data-end=\"1457\">Giải thích:</strong><br data-start=\"1457\" data-end=\"1460\">Nhiều doanh nhân lấy con người làm trung tâm bắt đầu kinh doanh vì trải nghiệm tiêu cực trước đó. Đây chính là lý do họ khởi nghiệp.</p>\n<hr data-start=\"1594\" data-end=\"1597\">\n<p data-start=\"1599\" data-end=\"1611\"><strong data-start=\"1602\" data-end=\"1611\">18. D</strong></p>\n<p data-start=\"1613\" data-end=\"1648\"><strong data-start=\"1613\" data-end=\"1624\">Vị trí:</strong> Đoạn D, câu gần cuối.</p>\n<p data-start=\"1650\" data-end=\"1766\"><strong data-start=\"1650\" data-end=\"1664\">Dẫn chứng:</strong><br data-start=\"1664\" data-end=\"1667\">“Working mothers still need to be taken more seriously, and so do mothers who are business owners.”</p>\n<p data-start=\"1768\" data-end=\"1968\"><strong data-start=\"1768\" data-end=\"1783\">Giải thích:</strong><br data-start=\"1783\" data-end=\"1786\">Hazel Gibbs nói rằng các bà mẹ đi làm và các nữ doanh nhân vẫn cần được coi trọng hơn. Điều này cho thấy một số nhóm vẫn đang đấu tranh để được tôn trọng trong môi trường kinh doanh.</p>"}]', 0);
INSERT INTO public.questions VALUES ('82a8f743-8084-4fd1-921c-ab6a236b6ae4', '512f7165-3186-4095-9dbb-1c7eb955294f', 'matrix', 'Questions 14-20', '', '<p>Which section contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a description of a barrier designed to stop dingoes, which also divides two kinds of non-native animals", "correctCategoryLetter": "E"}, {"itemText": "how dingoes ensure that rival species do not dominate", "correctCategoryLetter": "D"}, {"itemText": "a reference to a widespread non-native species that other animals feed on", "correctCategoryLetter": "C"}, {"itemText": "a mention of the dingo''s arrival in Australia", "correctCategoryLetter": "B"}, {"itemText": "research which has proved that dingoes have resorted to eating young livestock", "correctCategoryLetter": "F"}, {"itemText": "a description of a method used to kill dingoes", "correctCategoryLetter": "A"}, {"itemText": "the way that the structure of dingo groups affects how quickly their numbers grow", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. a description of a barrier designed to stop dingoes, which also divides two kinds of non-native animals — {E}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the world’s longest <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"35\">fence</strong>… it is there to keep dingoes out… the fence <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"89\">separates the main types of livestock</strong>… cattle… sheep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E mô tả hàng rào (barrier) dài 2.500 km dùng để ngăn dingo và chia cắt khu vực chăn nuôi bò (cattle) và cừu (sheep) — hai loài động vật không bản địa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. how dingoes ensure that rival species do not dominate — {D}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…dingoes are the solution… because they <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"56\">keep cat and fox populations under control</strong>. Besides regularly eating the smaller predators, dingoes will <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"161\">kill them simply to lessen competition</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chó dingo kiểm soát số lượng các loài đối thủ (mèo rừng, cáo) bằng cách ăn thịt hoặc giết chúng để giảm sự cạnh tranh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. a reference to a widespread non-native species that other animals feed on — {C}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"19\">rabbit</strong> was unleashed on Australia… Rabbits provide <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"72\">huge prey base for two other introduced species</strong>: the feral cat and the red fox.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thỏ là loài ngoại lai lan rộng và là nguồn thức ăn chính cho mèo và cáo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. a mention of the dingo’s arrival in Australia — {B}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “About <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"18\">4,000 years ago</strong>, Asian sailors <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"49\">introduced dingoes to Australia</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B nói về thời điểm và cách thức chó dingo đặt chân đến nước Úc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. research which has proved that dingoes have resorted to eating young livestock — {F}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…study… some of the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"36\">highest rates of calf predation occurred in areas that had been baited</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu của Lee Allen cho thấy ở những nơi bị đánh bả, các con dingo trẻ và đơn độc đã chuyển sang ăn thịt bê (young livestock) do không săn được kangaroo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. a description of a method used to kill dingoes — {A}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…drop 1,000 small pieces of meat… each piece <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"61\">laced with poison</strong>; this practice is known as <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"106\">baiting</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A mô tả phương pháp rải thịt tẩm thuốc độc (đánh bả) từ máy bay để tiêu diệt dingo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. the way that the structure of dingo groups affects how quickly their numbers grow — {D}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Dingo packs… generally have <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"42\">only one fertile female, which limits their rate of increase</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cấu trúc bầy đàn (chỉ một con cái sinh sản) giúp giới hạn tốc độ tăng trưởng số lượng của chúng.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('24bddbfc-7942-4906-8c22-bafa2b3137ef', '512f7165-3186-4095-9dbb-1c7eb955294f', 'matrix', 'Questions 21-23', '', '<p>Match each statement with the correct person (<strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>).</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "Dingoes tend to hunt native animals rather than hunting other non-native predators.", "correctCategoryLetter": "D"}, {"itemText": "The presence of dingoes puts the income of some people at risk.", "correctCategoryLetter": "A"}, {"itemText": "Dingoes have had little impact on the dying out of animal species in Australia.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Stuart McKechnie", "categoryLetter": "A"}, {"categoryText": "Chris Johnson", "categoryLetter": "B"}, {"categoryText": "Lee Allen", "categoryLetter": "C"}, {"categoryText": "Mark Clifford", "categoryLetter": "D"}]}', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">21. Dingoes tend to hunt native animals rather than hunting other non-native predators. — {D} Mark Clifford</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Clifford… is <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"27\">not convinced</strong> that they manage to catch cats that often, believing they are <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"103\">more likely to catch small native animals</strong> instead.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mark Clifford là người phản đối dingo. Ông không tin dingo giúp ích cho sinh thái bằng cách bắt mèo/cáo, mà cho rằng chúng sẽ ăn thịt các loài vật bản địa nhỏ (small native animals).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">22. The presence of dingoes puts the income of some people at risk. — {A} Stuart McKechnie</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Stuart McKechnie… complains that <strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"47\">graziers’ livelihoods are threatened</strong> when dingoes prey on cattle.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> McKechnie là quản lý trang trại, ông khẳng định sinh kế (livelihoods) hay thu nhập của nông dân bị đe dọa khi dingo săn bắt gia súc.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">23. Dingoes have had little impact on the dying out of animal species in Australia. — {B} Chris Johnson</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In the 4,000 years that dingoes have been Australia, they have contributed to <strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"90\">few, if any, extinctions</strong>, Johnson says.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Giáo sư Chris Johnson là người bảo vệ dingo. Ông đưa ra số liệu lịch sử rằng dingo rất ít khi (hoặc chưa từng) gây ra sự tuyệt chủng (extinction) cho các loài khác.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('d60f8828-1228-4f50-b78c-e6cd47e94ad8', 'dfe8748e-12ba-45d3-b622-91e5f3d4233d', 'checkbox', 'Questions 25 and 26', '', '<p data-start="1045" data-end="1073">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1075" data-end="1142">Which <strong>TWO </strong>mistakes did Mark and Stella make with their visuals?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. not taking enough care when making sketches"}, {"correct": false, "option_text": "B. not ensuring their photos had proper lighting"}, {"correct": true, "option_text": "C. not using anything to indicate the scale of their photos"}, {"correct": false, "option_text": "D. not making sufficient photos and drawings of things of interest"}, {"correct": true, "option_text": "E. not adequately recording when and where drawings were made"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('cf3cbaf7-f3bc-4522-ab4d-fd0c3abef2bb', '512f7165-3186-4095-9dbb-1c7eb955294f', 'fillup', 'Questions 24 - 26', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage.</p>
<ul>
<li>
<p data-path-to-node="45,0,0">The dingo replaced the {Tasmanian tiger} as the main predatory animal in Australia.</p>
</li>
<li>
<p data-path-to-node="45,1,0"> Foxes and cats are more likely to hunt native animals when there are fewer {rabbits}.</p>
</li>
<li>
<p data-path-to-node="45,2,0">Australian animals reproduce at a slow rate as a natural way of avoiding {overpopulation}.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">24. The dingo replaced the {Tasmanian tiger} as the main predatory animal in Australia.</strong></p>\n<ul data-path-to-node=\"7,0,1\">\n<li>\n<p data-path-to-node=\"7,0,1,0,0\"><strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as the <strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"22\">Tasmanian tiger</strong> disappeared completely from Australia, dingoes became Australia’s top predators.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,0,1,1,0\"><strong data-path-to-node=\"7,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi loài hổ Tasmania biến mất, dingo đã thế chỗ để trở thành loài săn mồi đầu bảng.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">25. Foxes and cats are more likely to hunt native animals when there are fewer {rabbits}.</strong></p>\n<ul data-path-to-node=\"7,1,1\">\n<li>\n<p data-path-to-node=\"7,1,1,0,0\"><strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “When bad seasons follow, <strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"37\">rabbit numbers are significantly reduced</strong> – and the… fox and cat populations are left with <strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"129\">little to eat besides native mammals</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,1,1,0\"><strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thỏ là nguồn thức ăn chính. Khi số lượng <strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"53\">thỏ (rabbits)</strong> giảm đi, cáo và mèo buộc phải quay sang săn các loài động vật bản địa để sinh tồn.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">26. Australian animals reproduce at a slow rate as a natural way of avoiding {overpopulation}.</strong></p>\n<ul data-path-to-node=\"7,2,1\">\n<li>\n<p data-path-to-node=\"7,2,1,0,0\"><strong data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Australian mammals generally reproduce much more slowly… an adaption to <strong data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"86\">prevent overpopulation</strong> in the arid environment…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,1,1,0\"><strong data-path-to-node=\"7,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sinh sản chậm là một cơ chế tự nhiên để tránh tình trạng <strong data-path-to-node=\"7,2,1,1,0\" data-index-in-node=\"74\">quá tải dân số (overpopulation)</strong> trong môi trường khắc nghiệt.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('f46d2d23-2833-4c6a-926f-52b4980fc077', '39099c50-f7c9-4428-8e76-be3ae7013f5b', 'fillup', 'Question 1 - 10', '<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer</p>
<table class="w-fit min-w-(--thread-content-width)" style="border-collapse: collapse; width: 100.063%; height: 310.828px; border: 1px solid rgb(0, 0, 0);" border="1" data-start="63" data-end="756">
<thead data-start="63" data-end="141">
<tr style="height: 70.1875px;" data-start="63" data-end="141">
